scwin.onpageload = async function() {

    scwin.memJson = $c.data.getMemInfo();
    scwin.pgrId = $c.data.getParameter("pgrId") == null? "tn_304_03_06b" : $c.data.getParameter("pgrId") ;

    scwin.strDate = WebSquare.date.getCurrentServerDate().substring(0, 6);
    scwin.strCurDate = WebSquare.date.getCurrentServerDate().substring(0, 8);
    scwin.chkFlag = "";
    scwin.userId = scwin.memJson.userId;
    scwin.userClsCd = scwin.memJson.userClsCd;
    scwin.userLobranCd = scwin.memJson.userLobranCd;
    scwin.sysAdminYn = scwin.memJson.sysAdminYn;
    scwin.vWrkPlCd = "";
    scwin.comboRtnFlag01 = false; //lc_wrkPlCd



     const codeOptions = [
        { grpCd : "OP317", compID : "lc_wrkPlCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.callbackCommon);

};

scwin.callbackCommon = async function(){

    lc_selDate.setSelectedIndex(1);

    if(scwin.userLobranCd == ("4AA")){			//인천지사
        scwin.vWrkPlCd = "4C01";
        lc_wrkPlCd.setSelectedIndex(0);
    }else if(scwin.userLobranCd == ("4BB")){	//경기지사
        scwin.vWrkPlCd = "4C02";
        lc_wrkPlCd.setSelectedIndex(1);
    }else if(scwin.userLobranCd == ("5AA")){	//전남지사
        scwin.vWrkPlCd = "5C08";
        lc_wrkPlCd.setSelectedIndex(2);
    }else{
        scwin.vWrkPlCd = "4C02";
        lc_wrkPlCd.setSelectedIndex(1);
    };

    if(scwin.sysAdminYn == 1){
		$c.gus.cfEnableObj(lc_wrkPlCd, true);
	}else{
		$c.gus.cfEnableObj(lc_wrkPlCd, false);
	};

    dma_search.set("fromDt", scwin.strCurDate);
    dma_search.set("toDt", scwin.strCurDate);
       var wrkPlcd = scwin.vWrkPlCd;
    await scwin.f_getBlockInfo(wrkPlcd);
     scwin.setWframe(); 
}

scwin.f_getBlockInfo = async function(wrkPlcd){

	//작업장 블럭정보 조회
    sbm_block.action = "/cm.zz.RetrieveComboCMD.do?sysCd=DsCommonEBC&queryId=retrieveMngBlockList&param1=" + wrkPlcd;
	// ds_block.DataId = "/cm.zz.RetrieveComboCMD.do?sysCd=DsCommonEBC/&queryId=retrieveMngBlockList&param1="+lc_wrkPlCd.BindColVal
	// ds_block.Reset();


	ds_block.removeAll();

    $c.sbm.execute(sbm_block);


};
scwin.sbm_block_submitdone = async function(){

     ds_block.sort("code",0);

    if(scwin.memJson.wrkPlCd == undefined || scwin.memJson.wrkPlCd == null || scwin.memJson.wrkPlCd == "") {
        lc_wrkPlCd.setSelectedIndex(1);
    } else {
        lc_wrkPlCd.setValue(scwin.memJson.wrkPlCd);
    }
};
scwin.f_Retrieve = function() {  

  	//dataSetDebug(ds_search, true);
     $c.sbm.execute(sbm_retrieve);
};
//-------------------------------------------------------------------------
//  저장
//-------------------------------------------------------------------------
scwin.f_Save = function(){

    var hasChanged = false;

    for (var dsRow = 0; dsRow <= ds_onOffSituation.getRowCount(); dsRow++) {

        // 실제 데이터 변경 여부 (수정 가능한 컬럼만)
        var isChanged =
            ds_onOffSituation.getCellData(dsRow, "wrkStsCd") !=
            ds_onOffSituation.getOriginalCellData(dsRow, "wrkStsCd")
            ||
            ds_onOffSituation.getCellData(dsRow, "indcLblock") !=
            ds_onOffSituation.getOriginalCellData(dsRow, "indcLblock");

        if (isChanged) {
            hasChanged = true;

            // 완료건 수정 방지
            if (! $c.gus.cfIsNull(ds_onOffSituation.getCellData(dsRow, "gatelogNo"))) {

                alert(
                    (ds_onOffSituation.getCellData(dsRow, "crryinoutClsCd") == "I"
                        ? "반입"
                        : "반출"
                    ) + "완료된 건은 수정이 불가 합니다."
                );

                // 해당 Row만 롤백
                ds_onOffSituation.undoRow(dsRow);
                return;
            }
             $c.sbm.execute(sbm_save);
        }
    }

    // 실제 변경된 데이터가 하나도 없을 경우
    if (!hasChanged) {
         $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }
};

