scwin.f_openPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {


    var rtnList = new Array();

    if (disGubun == "3"){ //LineretrieveLineInfo
        udc_lineCd.setSelectId("retrieveLineInfoList");
        rtnList = await udc_lineCd.cfCommonPopUp(scwin.callBackretrieveLineInfo
                            ,pCode,pName,pClose,null,null,null
                            ,null,null,null,null,null,null,null
                            ,pAllSearch,null);  
    }
};

scwin.callBackretrieveLineInfo = function(rtnList){
    $c.gus.cfSetReturnValue(rtnList, ed_lineCd, ed_lineNm, null);
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {

// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (! $c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
        $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal =  $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
}

