scwin.toolTip = function(rowIndex, colIndex, label, isOverflow, type){

    var value = "";
	if(colIndex == 22){//cntrStats
		if(ds_onOffSituation.getCellData(rowIndex, "lineCd") == "HTML"
		|| ds_onOffSituation.getCellData(rowIndex, "lineCd") == "EVER"
		|| ds_onOffSituation.getCellData(rowIndex, "lineCd") == "EMS"
		|| ds_onOffSituation.getCellData(rowIndex, "lineCd") == "ITS"
		|| ds_onOffSituation.getCellData(rowIndex, "lineCd") == "ANL"){
			value = "\n<< 더블클릭 >>\n\n 반출/입등록";

		}

	}
	if(colIndex == 21||colIndex == 23||colIndex == 8){

		if(ds_onOffSituation.getCellData(rowIndex,"wrkMemo") != ""){
			value = ds_onOffSituation.getCellData(rowIndex,"wrkMemo");

		}
	};
    return value;

}

scwin.gr_onOffSituation_oncelldblclick = async function (rowIndex, columnIndex, columnId) {

    var link_url = "";
    var link_title = "";
    var row = rowIndex;
    var programId = "";
    var params;
    var colid = columnId;
   if(colid == "cntrStats"){
		if(ds_onOffSituation.getCellData(row,"crryinoutClsCd") == "I"){
			link_url = "/ds/op/wrkrslts/cywrkrslts/op_301_01_05b.xml";
			link_title = "반입등록";
            programId = "op_301_01_05b";
            params = {
                wrkPlCd : lc_wrkPlCd.getValue()
            }
		}else{
			link_url = "/ds/op/wrkrslts/cywrkrslts/op_301_01_06b.xml";
			link_title = "반출등록";
            programId = "op_301_01_06b";
            params = {
                wrkPlCd : lc_wrkPlCd.getValue()
            }
		}

		//---------------------------------------------------------
		//상하차작업 완료건 && 강제등록이 아닌건 && 415에 실적이 없는건
		//---------------------------------------------------------
		if(ds_onOffSituation.getCellData(row,"wrkStsCd")  == "F"
		&& ds_onOffSituation.getCellData(row,"forceYn")   != "1"
		&& ds_onOffSituation.getCellData(row,"gatelogNo") == ""){
			link_url = link_url

            params = {
                odrNo : ds_onOffSituation.getCellData(row,"odrNo"),
                cntrNo : ds_onOffSituation.getCellData(row,"cntrNo")
            }

			//EVER(EMS,HTML,EVER,ITS), ANL라인의 수출상차건은 자동반출 불가
			//사무실에서 담당자가 SEAL_NO을 입력하여 수동으로 반출처리 해야한다.
			if((ds_onOffSituation.getCellData(row,"lineCd") == "EVER"
			 || ds_onOffSituation.getCellData(row,"lineCd") == "HTML"
			 || ds_onOffSituation.getCellData(row,"lineCd") == "EMS"
			 || ds_onOffSituation.getCellData(row,"lineCd") == "ITS")
			 || ds_onOffSituation.getCellData(row,"lineCd") == "ANL"){

				scwin.f_gotoTabMenu (strUrl, title, programId ,params);

             }
        }else{
            alert("반입/반출 대상건이 아닙니다.");
        }

	    //f_gotoTabMenu(url, title);
   }

   if(colid == "cntrNo"){
		if(ds_onOffSituation.getCellData(row,"wrkStsCd") == "F"){
            let strUrl = "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml";
            let programId = scwin.pgrId;

            let paramObj = {
                cntrNo : ds_onOffSituation.getCellData(row,"cntrNo"),
                pgrId : scwin.pgrId
            };

            $c.win.openMenu("컨테이너화물추적", strUrl, programId, paramObj , {openAction: "exist"});


		}
   }

   if(colid == "vehclNo"){
		//작업완료된 건을 차량번호 클릭시 컨테이너 운송지시 화면으로 전환시켜준다.
		var wrkStDt 	= scwin.f_setDate(ds_onOffSituation.getCellData(row,"crryinoutIntendDt"),-10);	//10일전 날짜로 세팅
		var wrkEndDt 	= scwin.f_setDate(ds_onOffSituation.getCellData(row,"reqWrkDt"),10);	//10일후 날짜로 세팅
		var gatelog  	= ds_onOffSituation.getCellData(row,"gatelogNo")
		var qryClsCd	= "N";

   		//gatelog가 없으면 미배차건으로 인식, 있으면 배차건으로 인식
   		if(!$c.gus.cfIsNull(gatelog)){	//배차건
   			qryClsCd	= "Y";
   		}
        if(ds_onOffSituation.getCellData(row,"wrkStsCd") == "F"){
            let strUrl = "/tn/op/transwrkindict/cntr/tn_304_01_01b.xml";
            let programId = scwin.pgrId;

            let paramObj = {
                cntrNo : ds_onOffSituation.getCellData(row,"cntrNo"),
                wrkStDt : wrkStDt,
                wrkEndDt : wrkEndDt,
                qryClsCd : qryClsCd,
                 pgrId : scwin.pgrId
            };

            $c.win.openMenu("컨테이너 운송지시", strUrl, programId, paramObj, {openAction: "exist"});
        };
   		// var remainQstr 	= "&qryClsCd=" + qryClsCd
		// if(ds_onOffSituation.NameValue(row,"wrkStsCd") == "F"){
		// 	cfTabMenuUpdate( "/tn/op/transwrkindict/cntr/tn_304_01_01b.jsp?cntrNo="
		// 	                + ds_onOffSituation.NameValue(row,"cntrNo")
		// 	                + "&wrkStDt=" + wrkStDt + "&wrkEndDt=" + wrkEndDt
		// 	                + remainQstr
		// 	                , "컨테이너 운송지시" ) ;
		// }
   }

};
scwin.changeform = function(e){

    var value;
    if(e == "1"){
        value = "Y"
    } else {
        value = "N"
    }

    return value;
}

scwin.gr_onOffSituation_onrowindexchange = function (rowIndex, oldRow) {

   var row = rowIndex;


    gr_onOffSituation.setCellColor(rowIndex, "carryinoutClsNm", "black" );
    gr_onOffSituation.setCellColor(rowIndex, "cntrNo", "black" );
    gr_onOffSituation.setCellColor(rowIndex, "wrkStsCd", "black" );
    gr_onOffSituation.setCellColor(rowIndex, "wrkMemo", "black" );


    for (var i = 0; i <= ds_onOffSituation.getRowCount(); i++ ){

        if(i != rowIndex){
                if(ds_onOffSituation.getCellData(i,"crryinoutClsCd") == "I"){

                gr_onOffSituation.setCellColor(i, "carryinoutClsNm", "black" );
                gr_onOffSituation.setCellColor(i, "wrkMemo", "black" );
                if(ds_onOffSituation.getCellData(i,"wrkStsCd") == "F"){
                    gr_onOffSituation.setCellColor(i, "cntrNo", "blue" );
                } else{
                    gr_onOffSituation.setCellColor(i, "cntrNo", "black" );
                }
            }else{

                gr_onOffSituation.setCellColor(i, "carryinoutClsNm", "red" );
                gr_onOffSituation.setCellColor(i, "cntrNo", "red" );
                gr_onOffSituation.setCellColor(i, "wrkMemo", "red" );
            };

            if (ds_onOffSituation.getCellData(i,"wrkStsCd") == "F") {
                gr_onOffSituation.setCellColor(i, "wrkStsCd", "green" );
                // gatelogNo 없음

            } else if(ds_onOffSituation.getCellData(i,"wrkStsCd") == "R"){
                gr_onOffSituation.setCellColor(i, "wrkStsCd", "blue" );
            } else {
                gr_onOffSituation.setCellColor(i, "wrkStsCd", "red" );
            } 

        }    
   }
};

