        return rtn;
};

scwin.cust3 = function(data, formattedData, rowIndex, colIndex){

    var rtn = "";
    var row = rowIndex;
     if(ds_onOffSituation.getCellData(row,"blNo") == "" || ds_onOffSituation.getCellData(row,"blNo") == null){
           rtn = ds_onOffSituation.getCellData(row,"bookingNo");

        } else{
           rtn = ds_onOffSituation.setCellData(row,"blBk", ds_onOffSituation.getCellData(row,"blNo"));
