};

scwin.setWframe = async function() {

    scwin.wframeParamData = { 
        "wrkPlCd" : scwin.vWrkPlCd

    }; 
    scwin.obj = { 
        "dataObject": {
            "type" : "json",
            "name" : "params",              
            "data" : scwin.wframeParamData
         }
    };

    var ret = await iCongestion.setSrc("/ui/tn/op/transwrkindict/cntr/tn_304_03_05p.xml", scwin.obj); 
}
